/* test_fmu.c — generated by sml2c.
 *
 * Smoke test: instantiate the FMU, transition through Init,
 * read back every parameter through fmi3Get*, free.
 * Exit code 0 = pass, non-zero = fail.
 *
 * Linked directly against the FMU library (no dlopen) to keep
 * the test plumbing small.  fmi3 functions are name-prefixed
 * with Foundation_ via FMI3_FUNCTION_PREFIX, so we set it before
 * including fmi3Functions.h.                                */
#define FMI3_FUNCTION_PREFIX Foundation_
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "fmi3Functions.h"
#include "model.h"

static void onLog(fmi3InstanceEnvironment env, fmi3Status status,
                  fmi3String category, fmi3String message) {
    (void)env;
    fprintf(stderr, "[%d %s] %s\n", (int)status,
            category ? category : "", message);
}

int main(void) {
    fmi3Instance c = fmi3InstantiateCoSimulation(
        "test", "", NULL,
        fmi3False, fmi3False, fmi3False, fmi3False,
        NULL, 0, NULL, onLog, NULL);
    if (!c) { fprintf(stderr, "instantiate failed\n"); return 1; }

    if (fmi3EnterInitializationMode(c, fmi3False, 0.0, 0.0,
                                   fmi3False, 0.0) != fmi3OK) {
        fprintf(stderr, "enter init failed\n"); return 2;
    }
    if (fmi3ExitInitializationMode(c) != fmi3OK) {
        fprintf(stderr, "exit init failed\n"); return 3;
    }

    int errors = 0;
    {
        fmi3ValueReference vr = 1;
        fmi3Float64 val = 0;
        if (fmi3GetFloat64(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get mass failed\n"); errors++;
        } else {
            printf("mass = %g\n", (double)val);
        }
    }
    {
        fmi3ValueReference vr = 2;
        fmi3Int64 val = 0;
        if (fmi3GetInt64(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get capacity failed\n"); errors++;
        } else {
            printf("capacity = %lld\n", (long long)val);
        }
    }
    {
        fmi3ValueReference vr = 3;
        fmi3String val = NULL;
        if (fmi3GetString(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get label failed\n"); errors++;
        } else {
            printf("label = %s\n", val ? val : "(null)");
        }
    }
    {
        fmi3ValueReference vr = 4;
        fmi3Boolean val = 0;
        if (fmi3GetBoolean(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get enabled failed\n"); errors++;
        } else {
            printf("enabled = %d\n", (int)val);
        }
    }

    fmi3Boolean evNeed = fmi3False, term = fmi3False, early = fmi3False;
    fmi3Float64 lastT = 0.0;
    if (fmi3DoStep(c, 0.0, 0.01, fmi3False,
                   &evNeed, &term, &early, &lastT) != fmi3OK) {
        fprintf(stderr, "DoStep failed\n"); errors++;
    }

    if (fmi3Terminate(c) != fmi3OK) errors++;
    fmi3FreeInstance(c);
    return errors == 0 ? 0 : 4;
}
